public boolean canBalance(int[] nums)
{
    int merlinL = 0;
    int merlinR = 0;

    for (int i = 0; i<nums.length; i++)
    {
         merlinR = merlinR + nums[i]; 
    }

    for (int i = 0; i<=nums.length - 2; i++)
    {
        merlinL = merlinL + nums[i];
        merlinR = merlinR - nums[i];
    }

    if (merlinL == merlinR)
    {
        return true;
    }

    return false;
}

