public boolean xyBalance(String str)
{
    int index1=0;
    int index2=0;
    for(int i=str.length();i>0;i--)
    {
        if (str.substring(i-2, i-1).equals("x"))
            {
                 index1= i;
             }
    }
    for(int i=str.length();i>0;i--)
    {
        if (str.substring(i-2, i-1).equals("y"))
        {
            index2= i;
        }                                           
    }
    return index1>index2;

}

