public int centeredAverage(int[] nums)
{
    int small = nums[0];
    int large = nums[0];
    int total = 0;

    for (int i = 0; i < nums.length; i++)
    {
        total = total + nums[i];
        if (nums[i] > large)
        {
            large = nums[i];
        }
        if (nums[i] < small) 
        {
            small = nums[i];
        }
    }
    return (total - (large + small)) / (nums.length - 2);
}
